import { useEffect, useState } from "react";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:8000";

export default function AdminFood() {
  const [activeTab, setActiveTab] = useState("food-items");
  const [foodName, setFoodName] = useState("");
  const [category, setCategory] = useState("");
  const [price, setPrice] = useState("");
  const [image, setImage] = useState(null);
  const [preview, setPreview] = useState(null);
  const [foods, setFoods] = useState([]);
  const [orders, setOrders] = useState([]);
  const [orderStats, setOrderStats] = useState({});
  const [selectedMonth, setSelectedMonth] = useState("");
  const [availableMonths, setAvailableMonths] = useState([]);

  const [loading, setLoading] = useState(false);
  const [msg, setMsg] = useState("");
  const [error, setError] = useState("");

  useEffect(() => {
    fetchFoods();
    fetchOrderStats();
    fetchAvailableMonths();
  }, []);

  useEffect(() => {
    if (activeTab === "order-history" && selectedMonth) {
      const [year, month] = selectedMonth.split("-");
      fetchOrdersByMonth(year, month);
    }
  }, [activeTab, selectedMonth]);

  const fetchFoods = async () => {
    try {
      const res = await axios.get(`${API_BASE}/api/food/`);
      setFoods(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const fetchOrderStats = async () => {
    try {
      const res = await axios.get(`${API_BASE}/api/food-orders/stats/`);
      setOrderStats(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const fetchAvailableMonths = async () => {
    try {
      const res = await axios.get(`${API_BASE}/api/food-orders/months/`);
      setAvailableMonths(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const fetchOrdersByMonth = async (year, month) => {
    try {
      const res = await axios.get(`${API_BASE}/api/food-orders/history/${year}/${month}/`);
      setOrders(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const handleImageChange = (e) => {
    const file = e.target.files[0];
    setImage(file);
    if (file) setPreview(URL.createObjectURL(file));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMsg("");
    setError("");

    if (!foodName || !category || !price || !image) {
      setError("Please fill all fields.");
      return;
    }

    const fd = new FormData();
    fd.append("name", foodName);
    fd.append("category", category);
    fd.append("price", price);
    fd.append("image", image);

    try {
      setLoading(true);
      await axios.post(`${API_BASE}/api/food/`, fd, {
        headers: { "Content-Type": "multipart/form-data" },
      });

      setMsg("✅ Food item added successfully!");
      setFoodName("");
      setCategory("");
      setPrice("");
      setImage(null);
      setPreview(null);
      fetchFoods();
    } catch (err) {
      setError("❌ Failed to add food.");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this food item?")) return;

    try {
      await axios.delete(`${API_BASE}/api/food/${id}/`);
      setFoods((prev) => prev.filter((f) => f.id !== id));
    } catch (err) {
      alert("Failed to delete food");
    }
  };

  const handleUpdateOrderStatus = async (orderId, newStatus) => {
    try {
      await axios.patch(`${API_BASE}/api/food-orders/${orderId}/`, { status: newStatus });
      setOrders(orders.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
    } catch (err) {
      alert("Failed to update order status");
    }
  };

  const getMonthOptions = () => {
    const months = [];
    const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
    const now = new Date();
    for (let i = 0; i < 12; i++) {
      const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
      const value = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      const label = `${monthNames[d.getMonth()]} ${d.getFullYear()}`;
      months.push({ value, label });
    }
    return months;
  };

  return (
    <div>
      <style>{`
        :root {
          --bg-dark: #181818;
          --bg-sidebar: #202020;
          --text-light: #f1f1f1;
          --text-muted: #aaa;
          --accent: #c89d5c;
          --card-bg: #2a2a2a;
        }
        *{box-sizing:border-box;font-family:"Segoe UI",sans-serif}
        .page{display:flex;min-height:100vh;background:var(--bg-dark);color:var(--text-light)}
        .sidebar-container{width:220px;min-height:100vh;background:var(--bg-sidebar);padding:20px;display:flex;flex-direction:column;position:fixed;top:0;left:0;height:100vh}
        .sidebar-title{color:var(--accent);font-size:20px;margin-bottom:24px;font-weight:600}
        .sidebar-nav{display:flex;flex-direction:column;flex:1}
        .sidebar-link{color:var(--muted);text-decoration:none;padding:10px 12px;border-radius:6px;margin-bottom:4px;transition:all 0.2s ease;display:block}
        .sidebar-link:hover{color:var(--accent);background:rgba(200,157,92,0.1)}
        .sidebar-link.active{background:rgba(200,157,92,0.15);color:var(--accent)}
        .sidebar-logout{margin-top:auto;padding-top:20px;border-top:1px solid #333}
        .main-content{flex:1;margin-left:220px;padding:28px;min-height:100vh}
        h1,h2{color:var(--accent)}
        .tabs{display:flex;gap:10px;margin-bottom:20px}
        .tab-btn{padding:10px 20px;background:var(--card-bg);border:none;color:var(--text-light);cursor:pointer;border-radius:6px}
        .tab-btn.active{background:var(--accent);color:#111}
        form, table, .stats-grid{
          background:var(--card-bg);
          padding:16px;
          border-radius:8px;
          margin-bottom:20px;
        }
        label{
          display:block;
          color:var(--text-muted);
          font-size:13px;
          margin-top:8px;
        }
        input, select, textarea{
          width:100%;
          padding:10px;
          margin-top:6px;
          border-radius:6px;
          border:none;
          background:#3e3e3e;
          color:#fff;
        }
        .btn{
          margin-top:14px;
          background:var(--accent);
          color:#111;
          padding:10px 14px;
          border-radius:6px;
          border:none;
          cursor:pointer;
        }
        .btn-delete{
          background:#e53935;
          color:#fff;
          border:none;
          padding:6px 10px;
          border-radius:6px;
          cursor:pointer;
        }
        .btn-status{
          padding:4px 8px;
          border-radius:4px;
          border:none;
          cursor:pointer;
          font-size:12px;
          margin-right:4px;
        }
        table{width:100%;border-collapse:collapse}
        th,td{padding:12px;border-bottom:1px solid #333}
        th{color:var(--accent);text-align:left}
        img.thumb{
          width:80px;
          height:60px;
          object-fit:cover;
          border-radius:4px;
        }
        .stats-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin-bottom:20px}
        .stat-card{background:var(--card-bg);padding:20px;border-radius:8px;text-align:center}
        .stat-card h3{color:var(--text-muted);font-size:14px;margin-bottom:8px}
        .stat-card p{color:var(--accent);font-size:24px;font-weight:bold}
        .order-status{padding:4px 10px;border-radius:12px;font-size:12px}
        .status-pending{background:#fbbf24;color:#000}
        .status-preparing{background:#60a5fa;color:#fff}
        .status-ready{background:#34d399;color:#000}
        .status-delivered{background:#10b981;color:#fff}
        .status-cancelled{background:#ef4444;color:#fff}
        @media (max-width:900px){
          .sidebar-container{display:none}
          .main-content{margin-left:0}
          .stats-grid{grid-template-columns:repeat(2,1fr)}
        }
      `}</style>

      <div className="page">
        <aside className="sidebar-container">
          <h2 className="sidebar-title">Admin</h2>
          <nav className="sidebar-nav">
            <a href="/admin" className="sidebar-link">Dashboard</a>
            <a href="/admin/reservations" className="sidebar-link">Reservations</a>
            <a href="/admin/rooms" className="sidebar-link">Rooms</a>
            <a href="/admin/guest-activity" className="sidebar-link">Guest Activity</a>
            <a href="/admin/staff" className="sidebar-link">Staff</a>
            <a href="/admin/gallery" className="sidebar-link">Gallery</a>
            <a href="/admin/food" className="sidebar-link active">Food</a>
          </nav>
          <div className="sidebar-logout">
            <a href="/login" className="sidebar-link">Logout</a>
          </div>
        </aside>

        <main className="main-content">
          <h1>Food Management</h1>

          <div className="tabs">
            <button 
              className={`tab-btn ${activeTab === 'food-items' ? 'active' : ''}`}
              onClick={() => setActiveTab('food-items')}
            >
              Food Items
            </button>
            <button 
              className={`tab-btn ${activeTab === 'order-history' ? 'active' : ''}`}
              onClick={() => setActiveTab('order-history')}
            >
              Order History
            </button>
          </div>

          {msg && <div style={{ color: "#9ef59e" }}>{msg}</div>}
          {error && <div style={{ color: "#ff8a8a" }}>{error}</div>}

          {/* FOOD ITEMS TAB */}
          {activeTab === 'food-items' && (
            <>
              <form onSubmit={handleSubmit}>
                <label>Food Name</label>
                <input value={foodName} onChange={(e) => setFoodName(e.target.value)} />

                <label>Category</label>
                <select value={category} onChange={(e) => setCategory(e.target.value)}>
                  <option value="">Select</option>
                  <option value="bread">Bread</option>
                  <option value="drinks">Drinks</option>
                  <option value="veg">Veg</option>
                  <option value="non-veg">Non Veg</option>
                  <option value="dessert">Dessert</option>
                </select>

                <label>Price (₹)</label>
                <input
                  type="number"
                  value={price}
                  onChange={(e) => setPrice(e.target.value)}
                />

                <label>Image</label>
                <input type="file" onChange={handleImageChange} />

                <button className="btn" disabled={loading}>
                  {loading ? "Adding..." : "Add Food"}
                </button>
              </form>

              <h2>Food Items</h2>

              {foods.length === 0 ? (
                <p>No food items added.</p>
              ) : (
                <table>
                  <thead>
                    <tr>
                      <th>ID</th>
                      <th>Image</th>
                      <th>Name</th>
                      <th>Category</th>
                      <th>Price</th>
                      <th>Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {foods.map((f) => (
                      <tr key={f.id}>
                        <td>{f.id}</td>
                        <td>
                          <img
                            src={f.image_url || `${API_BASE}${f.image}`}
                            alt={f.name}
                            className="thumb"
                          />
                        </td>
                        <td>{f.name}</td>
                        <td>{f.category}</td>
                        <td>₹{f.price}</td>
                        <td>
                          <button
                            className="btn-delete"
                            onClick={() => handleDelete(f.id)}
                          >
                            Delete
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </>
          )}

          {/* ORDER HISTORY TAB */}
          {activeTab === 'order-history' && (
            <>
              <div className="stats-grid">
                <div className="stat-card">
                  <h3>Today's Orders</h3>
                  <p>{orderStats.today_count || 0}</p>
                </div>
                <div className="stat-card">
                  <h3>Today's Revenue</h3>
                  <p>₹{orderStats.today_revenue || 0}</p>
                </div>
                <div className="stat-card">
                  <h3>This Month</h3>
                  <p>{orderStats.month_count || 0}</p>
                </div>
                <div className="stat-card">
                  <h3>Month Revenue</h3>
                  <p>₹{orderStats.month_revenue || 0}</p>
                </div>
              </div>

              <div style={{ marginBottom: 20 }}>
                <label>Select Month</label>
                <select 
                  value={selectedMonth} 
                  onChange={(e) => setSelectedMonth(e.target.value)}
                >
                  <option value="">Select a month</option>
                  {getMonthOptions().map((m) => (
                    <option key={m.value} value={m.value}>{m.label}</option>
                  ))}
                </select>
              </div>

              {selectedMonth && (
                <>
                  <h2>Orders - {getMonthOptions().find(m => m.value === selectedMonth)?.label}</h2>
                  {orders.length === 0 ? (
                    <p>No orders for this month.</p>
                  ) : (
                    <table>
                      <thead>
                        <tr>
                          <th>Order ID</th>
                          <th>Guest</th>
                          <th>Room</th>
                          <th>Food Item</th>
                          <th>Qty</th>
                          <th>Total</th>
                          <th>Status</th>
                          <th>Date</th>
                        </tr>
                      </thead>
                      <tbody>
                        {orders.map((o) => (
                          <tr key={o.id}>
                            <td>#{o.id}</td>
                            <td>{o.guest_name}<br/><small>{o.guest_phone}</small></td>
                            <td>{o.room_info}</td>
                            <td>{o.food_name}</td>
                            <td>{o.quantity}</td>
                            <td>₹{o.total_price}</td>
                            <td>
                              <span className={`order-status status-${o.status}`}>
                                {o.status}
                              </span>
                            </td>
                            <td>{new Date(o.created_at).toLocaleDateString()}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  )}
                </>
              )}
            </>
          )}
        </main>
      </div>
    </div>
  );
}
